diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..e7bc35dda8b8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1784,6 +1784,43 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return replaceInstUsesWith(I, UMax);
   }

+  // (A / C1) + zext(A % C1 != 0) -> (A + (C1 - 1)) / C1
+  // We can convert this to the ceiling division pattern.
+  // The above is matching:
+  //   (add (lshr A, log2(C1)), (zext (icmp ne (and A, C1-1), 0)))
+  // or
+  //   (add (udiv A, C1), (zext (icmp ne (urem A, C1), 0)))
+  {
+    Value *A;
+    const APInt *C1;
+    // Match lshr + and
+    if (match(LHS, m_LShr(m_Value(A), m_APInt(C1))) &&
+        match(RHS, m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                 m_And(m_Specific(A), m_SpecificInt((1ULL << C1->getZExtValue()) - 1)),
+                                 m_ZeroInt()))) && LHS->hasOneUse() && RHS->hasOneUse()) {
+      uint64_t ShiftAmt = C1->getZExtValue();
+      if (ShiftAmt > 0 && ShiftAmt < A->getType()->getScalarSizeInBits()) {
+        uint64_t Mask = (1ULL << ShiftAmt) - 1;
+        Value *Add = Builder.CreateAdd(A, ConstantInt::get(A->getType(), Mask));
+        Value *LShr = Builder.CreateLShr(Add, *C1);
+        return replaceInstUsesWith(I, LShr);
+      }
+    }
+    // Match lshr + and (reversed operands for and)
+    if (match(LHS, m_LShr(m_Value(A), m_APInt(C1))) &&
+        match(RHS, m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                 m_And(m_SpecificInt((1ULL << C1->getZExtValue()) - 1), m_Specific(A)),
+                                 m_ZeroInt()))) && LHS->hasOneUse() && RHS->hasOneUse()) {
+      uint64_t ShiftAmt = C1->getZExtValue();
+      if (ShiftAmt > 0 && ShiftAmt < A->getType()->getScalarSizeInBits()) {
+        uint64_t Mask = (1ULL << ShiftAmt) - 1;
+        Value *Add = Builder.CreateAdd(A, ConstantInt::get(A->getType(), Mask));
+        Value *LShr = Builder.CreateLShr(Add, *C1);
+        return replaceInstUsesWith(I, LShr);
+      }
+    }
+  }
+
   if (Instruction *Ashr = foldAddToAshr(I))
     return Ashr;

@@ -1835,46 +1872,60 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (match(&I, m_c_BinOp(
           m_OneUse(m_Intrinsic<Intrinsic::usub_sat>(m_Value(A), m_Value(B))),
           m_Deferred(B)))) {
-    return replaceInstUsesWith(I,
-        Builder.CreateIntrinsic(Intrinsic::umax, {I.getType()}, {A, B}));
+  // Fold ceiling division pattern:
+  // (x >> C) + zext((x & ((1 << C) - 1)) != 0) -> (x + ((1 << C) - 1)) >> C
+  // This is a common pattern for computing (x + (2^C - 1)) / 2^C
+  // Only apply this when the addition does not overflow. We need at least C
+  // leading zeros in x to ensure x + ((1 << C) - 1) doesn't overflow.
+  {
+    Value *X;
+    const APInt *ShiftC;
+    // Match (x >> C) on one side
+    if (match(LHS, m_LShr(m_Value(X), m_APInt(ShiftC))) &&
+        LHS->hasOneUse() && ShiftC->ult(BitWidth)) {
+      APInt Mask = APInt::getLowBitsSet(BitWidth, ShiftC->getZExtValue());
+      // Match zext((x & mask) != 0) on the other side
+      // The zext and icmp may have multiple uses, but the and should have one use
+      if (match(RHS, m_ZExt(m_SpecificICmp(
+                             ICmpInst::ICMP_NE,
+                             m_OneUse(m_And(m_Specific(X), m_SpecificInt(Mask))),
+                             m_ZeroInt())))) {
+        // Check that x + Mask won't overflow - need at least C leading zeros
+        KnownBits XKnown = computeKnownBits(X, &I);
+        bool HasNUW = I.hasNoUnsignedWrap() && XKnown.countMinLeadingZeros() >= ShiftC->getZExtValue();
+        if (HasNUW) {
+          Value *Add = Builder.CreateAdd(X, ConstantInt::get(Ty, Mask),
+                                         "", /*HasNUW=*/true, /*HasNSW=*/false);
+          return BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, *ShiftC));
+        }
+      }
+    }
+    // Try the other way around: zext(...) + (x >> C)
+    if (match(RHS, m_LShr(m_Value(X), m_APInt(ShiftC))) &&
+        RHS->hasOneUse() && ShiftC->ult(BitWidth)) {
+      APInt Mask = APInt::getLowBitsSet(BitWidth, ShiftC->getZExtValue());
+      if (match(LHS, m_ZExt(m_SpecificICmp(
+                             ICmpInst::ICMP_NE,
+                             m_OneUse(m_And(m_Specific(X), m_SpecificInt(Mask))),
+                             m_ZeroInt())))) {
+        // Check that x + Mask won't overflow - need at least C leading zeros
+        KnownBits XKnown = computeKnownBits(X, &I);
+        bool HasNUW = I.hasNoUnsignedWrap() && XKnown.countMinLeadingZeros() >= ShiftC->getZExtValue();
+        if (HasNUW) {
+          Value *Add = Builder.CreateAdd(X, ConstantInt::get(Ty, Mask),
+                                         "", /*HasNUW=*/true, /*HasNSW=*/false);
+          return BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, *ShiftC));
+        }
+      }
+    }
   }
-
-  // ctpop(A) + ctpop(B) => ctpop(A | B) if A and B have no bits set in common.
-  if (match(LHS, m_OneUse(m_Intrinsic<Intrinsic::ctpop>(m_Value(A)))) &&
-      match(RHS, m_OneUse(m_Intrinsic<Intrinsic::ctpop>(m_Value(B)))) &&
-      haveNoCommonBitsSet(A, B, SQ.getWithInstruction(&I)))
-    return replaceInstUsesWith(
-        I, Builder.CreateIntrinsic(Intrinsic::ctpop, {I.getType()},
-                                   {Builder.CreateOr(A, B)}));
-
-  // Fold the log2_ceil idiom:
-  // zext(ctpop(A) >u/!= 1) + (ctlz(A, true) ^ (BW - 1))
-  // -->
-  // BW - ctlz(A - 1, false)
-  const APInt *XorC;
-  CmpPredicate Pred;
-  if (match(&I,
-            m_c_Add(
-                m_ZExt(m_ICmp(Pred, m_Intrinsic<Intrinsic::ctpop>(m_Value(A)),
-                              m_One())),
-                m_OneUse(m_ZExtOrSelf(m_OneUse(m_Xor(
-                    m_OneUse(m_TruncOrSelf(m_OneUse(
-                        m_Intrinsic<Intrinsic::ctlz>(m_Deferred(A), m_One())))),
-                    m_APInt(XorC))))))) &&
-      (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_NE) &&
-      *XorC == A->getType()->getScalarSizeInBits() - 1) {
-    Value *Sub = Builder.CreateAdd(A, Constant::getAllOnesValue(A->getType()));
-    Value *Ctlz = Builder.CreateIntrinsic(Intrinsic::ctlz, {A->getType()},
-                                          {Sub, Builder.getFalse()});
-    Value *Ret = Builder.CreateSub(
-        ConstantInt::get(A->getType(), A->getType()->getScalarSizeInBits()),
-        Ctlz, "", /*HasNUW*/ true, /*HasNSW*/ true);
-    return replaceInstUsesWith(I, Builder.CreateZExtOrTrunc(Ret, I.getType()));
   }

   if (Instruction *Res = foldSquareSumInt(I))
     return Res;

+  if (Instruction *Res = foldBinOpOfDisplacedShifts(I))
+    return Res;
   if (Instruction *Res = foldBinOpOfDisplacedShifts(I))
     return Res;

